80	    fn from_messages(messages: Vec<MessageRecord>) -> Self {
81	        let mut project_map: HashMap<(SourceKind, String), ProjectAggregateState> = HashMap::new();
82	        let mut session_map: HashMap<(SourceKind, String, String), SessionAggregateState> =
83	            HashMap::new();
84	
85	        for message in &messages {
86	            let project_key = (message.source, message.project_name.clone());
87	            let project_state =
88	                project_map
89	                    .entry(project_key)
90	                    .or_insert_with(|| ProjectAggregateState {
91	                        source: message.source,
92	                        name: message.project_name.clone(),
93	                        original_path: message.project_path.clone(),
94	                        last_activity: message.timestamp.clone(),
95	                        message_count: 0,
96	                        session_ids: HashSet::new(),
97	                    });
98	
99	            project_state.message_count += 1;
100	            project_state.session_ids.insert(message.session_id.clone());
101	            if project_state.original_path.is_empty() && !message.project_path.is_empty() {
102	                project_state.original_path = message.project_path.clone();
103	            }
104	            if message.timestamp > project_state.last_activity {
105	                project_state.last_activity = message.timestamp.clone();
106	            }
107	
108	            let session_key = (
109	                message.source,
110	                message.project_name.clone(),
111	                message.session_id.clone(),
112	            );
113	            let session_state =
114	                session_map
115	                    .entry(session_key)
116	                    .or_insert_with(|| SessionAggregateState {
117	                        project_name: message.project_name.clone(),
118	                        project_path: message.project_path.clone(),
119	                        source: message.source,
120	                        session_id: message.session_id.clone(),
121	                        first_timestamp: message.timestamp.clone(),
122	                        last_timestamp: message.timestamp.clone(),
123	                        message_count: 0,
124	                        user_messages: 0,
125	                        assistant_messages: 0,
126	                        preview: None,
127	                    });
128	
129	            session_state.message_count += 1;
130	            if session_state.project_path.is_empty() && !message.project_path.is_empty() {
131	                session_state.project_path = message.project_path.clone();
132	            }
133	            if message.timestamp < session_state.first_timestamp {
134	                session_state.first_timestamp = message.timestamp.clone();
135	            }
136	            if message.timestamp > session_state.last_timestamp {
137	                session_state.last_timestamp = message.timestamp.clone();
138	            }
139	
140	            if message.role == "user" {
141	                session_state.user_messages += 1;
142	                let candidate = PreviewCandidate {
143	                    timestamp: message.timestamp.clone(),
144	                    source_file: message.source_file.clone(),
145	                    line_index: message.line_index,
146	                    content: message.content.clone(),
147	                };
148	                let should_replace = session_state
149	                    .preview
150	                    .as_ref()
151	                    .map(|current| preview_cmp(&candidate, current) == Ordering::Less)
152	                    .unwrap_or(true);
153	                if should_replace {
154	                    session_state.preview = Some(candidate);
155	                }
156	            }
157	
158	            if message.role == "assistant" {
159	                session_state.assistant_messages += 1;
160	            }
161	        }
162	
163	        let projects = project_map
164	            .into_values()
165	            .map(|state| ProjectAggregate {
166	                name: state.name,
167	                source: state.source,
168	                original_path: state.original_path,
169	                session_count: state.session_ids.len() as i32,
170	                message_count: state.message_count,
171	                last_activity: state.last_activity,
172	            })
173	            .collect::<Vec<_>>();
174	
175	        let sessions = session_map
176	            .into_values()
177	            .map(|state| SessionAggregate {
178	                project_name: state.project_name,
179	                project_path: state.project_path,
180	                source: state.source,
181	                session_id: state.session_id,
182	                first_timestamp: state.first_timestamp,
183	                last_timestamp: state.last_timestamp,
184	                message_count: state.message_count,
185	                user_messages: state.user_messages,
186	                assistant_messages: state.assistant_messages,
187	                preview: truncate_preview(
188	                    &state
189	                        .preview
190	                        .map(|preview| preview.content)
191	                        .unwrap_or_default(),
192	                    120,
193	                ),
194	            })
195	            .collect::<Vec<_>>();
196	
197	        Self {
198	            messages,
199	            projects,
200	            sessions,
201	        }
202	    }
