204	    pub fn projects(
205	        &self,
206	        source_filter: Option<SourceFilter>,
207	        limit: Option<usize>,
208	        offset: usize,
209	        sort: SortOptions,
210	    ) -> ApiProjectsResponse {
211	        let mut filtered = self
212	            .projects
213	            .iter()
214	            .filter(|project| matches_source_filter(project.source, source_filter))
215	            .cloned()
216	            .collect::<Vec<_>>();
217	        sort_projects(&mut filtered, sort.by, sort.order);
218	
219	        let projects = apply_pagination(filtered, limit, offset)
220	            .into_iter()
221	            .map(|project| ApiProject {
222	                name: project.name.clone(),
223	                source: project.source.as_str().to_string(),
224	                original_path: project.original_path.clone(),
225	                aliases: project_lookup_aliases(&project.name, &project.original_path),
