230	            .collect::<Vec<_>>();
231	
232	        let total_messages = self
233	            .messages
234	            .iter()
235	            .filter(|message| matches_source_filter(message.source, source_filter))
236	            .count() as i64;
237	        let total_sessions = self
238	            .sessions
239	            .iter()
240	            .filter(|session| matches_source_filter(session.source, source_filter))
241	            .count() as i64;
242	
243	        ApiProjectsResponse {
244	            projects,
245	            total_messages,
246	            total_sessions,
247	        }
