298	    pub fn messages(
299	        &self,
300	        session_id: Option<&str>,
301	        project: Option<&str>,
302	        source_filter: Option<SourceFilter>,
303	        options: MessageQueryOptions,
304	    ) -> Result<ApiMessagesResponse> {
305	        let resolved_project = match project {
306	            Some(project) => Some(resolve_project(&self.projects, source_filter, project)?),
307	            None => None,
308	        };
309	
310	        let mut filtered = self
311	            .messages
312	            .iter()
313	            .filter(|message| {
314	                matches_source_filter(message.source, source_filter)
315	                    && matches_session_filter(message.session_id.as_str(), session_id)
316	                    && matches_message_project_filter(message, resolved_project.as_ref())
317	            })
318	            .cloned()
319	            .collect::<Vec<_>>();
320	        let total_messages = filtered.len() as i64;
321	        let session_message_counts = build_session_message_counts(&filtered);
322	        sort_messages(
323	            &mut filtered,
324	            options.sort.by,
325	            options.sort.order,
326	            &session_message_counts,
327	        );
328	        let selected_total = options
329	            .message_index_range
330	            .map(|range| message_index_range_len(filtered.len(), range))
331	            .unwrap_or(filtered.len());
332	        let filtered = apply_message_index_range(filtered, options.message_index_range);
333	
334	        let paged = if options.sort.by == SortBy::Timestamp && options.sort.order == SortOrder::Asc
335	        {
336	            // Preserve the historical "newest window, then chronological output" behavior.
337	            let descending = filtered.into_iter().rev().collect::<Vec<_>>();
338	            let mut paged = apply_pagination(descending, options.limit, options.offset);
339	            paged.reverse();
340	            paged
341	        } else {
342	            apply_pagination(filtered, options.limit, options.offset)
343	        };
344	
345	        let page_size = paged.len();
346	        let next_offset = (options.offset + page_size) as i64;
347	        let next_page = options.limit.is_some() && next_offset < selected_total as i64;
348	
349	        let messages = paged
350	            .into_iter()
351	            .map(|message| ApiMessage {
352	                session_id: message.session_id,
353	                source: message.source.as_str().to_string(),
354	                project_name: message.project_name,
355	                role: message.role,
356	                content: message.content,
357	                model: message.model,
358	                timestamp: message.timestamp,
359	                is_subagent: message.is_subagent,
360	                msg_type: message.msg_type,
361	                input_tokens: message.input_tokens,
362	                output_tokens: message.output_tokens,
363	            })
364	            .collect();
365	
366	        Ok(ApiMessagesResponse {
367	            messages,
368	            total_messages,
369	            next_page,
370	            next_offset,
371	            next_command: None,
372	        })
373	    }
