375	    pub fn resolve_teleport_session(
376	        &self,
377	        session_id: Option<&str>,
378	        project: Option<&str>,
379	        source_filter: Option<SourceFilter>,
380	    ) -> Result<TeleportSessionContext> {
381	        let resolved_project = match project {
382	            Some(project) => Some(resolve_project(&self.projects, source_filter, project)?),
383	            None => None,
384	        };
385	
386	        let mut filtered = self
387	            .sessions
388	            .iter()
389	            .filter(|session| {
390	                matches_source_filter(session.source, source_filter)
391	                    && matches_project_filter(session, resolved_project.as_ref())
392	            })
393	            .cloned()
394	            .collect::<Vec<_>>();
395	        sort_sessions(&mut filtered, SortBy::Timestamp, SortOrder::Desc);
396	
397	        let mut candidates = filtered
398	            .into_iter()
399	            .map(|session| ApiSession {
400	                session_id: session.session_id,
401	                source: session.source.as_str().to_string(),
402	                project_name: session.project_name,
403	                project_path: session.project_path,
404	                first_timestamp: session.first_timestamp,
405	                last_timestamp: session.last_timestamp,
406	                message_count: session.message_count,
407	                user_messages: session.user_messages,
408	                assistant_messages: session.assistant_messages,
409	                preview: session.preview,
410	            })
411	            .collect::<Vec<_>>();
412	        if let Some(session_id) = session_id {
413	            candidates.retain(|session| session.session_id == session_id);
414	            if candidates.is_empty() {
415	                bail!("session {session_id} not found in scope");
416	            }
417	            if candidates.len() > 1 {
418	                bail!(
419	                    "multiple sessions matched session id {session_id}; pass --project or --source"
420	                );
421	            }
422	        } else if candidates.is_empty() {
423	            bail!("no sessions found in scope");
424	        } else {
425	            candidates.truncate(1);
426	        }
427	
428	        let session = candidates
429	            .into_iter()
430	            .next()
431	            .expect("teleport session candidate");
432	        let source_file = self
433	            .messages
434	            .iter()
435	            .filter(|message| {
436	                message.session_id == session.session_id
437	                    && message.project_name == session.project_name
438	                    && message.source.as_str() == session.source
439	            })
440	            .map(|message| message.source_file.clone())
441	            .min()
442	            .map(PathBuf::from)
443	            .with_context(|| {
444	                format!(
445	                    "native transcript path missing for session {}",
446	                    session.session_id
447	                )
448	            })?;
449	
450	        Ok(TeleportSessionContext {
451	            session,
452	            source_file,
453	        })
454	    }
