456	    pub fn latest_session_messages(
457	        &self,
458	        session_id: Option<&str>,
459	        project: Option<&str>,
460	        source_filter: Option<SourceFilter>,
461	        window: usize,
462	        message_index_range: Option<MessageIndexRange>,
463	    ) -> Result<ApiMessagesResponse> {
464	        let resolved_project = match project {
465	            Some(project) => Some(resolve_project(&self.projects, source_filter, project)?),
466	            None => None,
467	        };
468	
469	        let scoped = self
470	            .messages
471	            .iter()
472	            .filter(|message| {
473	                matches_source_filter(message.source, source_filter)
474	                    && matches_session_filter(message.session_id.as_str(), session_id)
475	                    && matches_message_project_filter(message, resolved_project.as_ref())
476	            })
477	            .collect::<Vec<_>>();
478	
479	        let Some(latest) = scoped
480	            .iter()
481	            .max_by(|a, b| latest_session_message_cmp(a, b))
482	        else {
483	            return Ok(ApiMessagesResponse {
484	                messages: Vec::new(),
485	                total_messages: 0,
486	                next_page: false,
487	                next_offset: 0,
488	                next_command: None,
489	            });
490	        };
491	        let latest_key = (
492	            latest.source,
493	            latest.project_name.clone(),
494	            latest.session_id.clone(),
495	        );
496	
497	        let mut latest_session_messages = scoped
498	            .into_iter()
499	            .filter(|message| session_key(message) == latest_key)
500	            .cloned()
501	            .collect::<Vec<_>>();
502	        sort_messages(
503	            &mut latest_session_messages,
504	            SortBy::Timestamp,
505	            SortOrder::Asc,
506	            &HashMap::new(),
507	        );
508	
509	        let total_messages = latest_session_messages.len() as i64;
510	        let ranged = apply_message_index_range(latest_session_messages, message_index_range);
511	        let mut windowed = ranged.into_iter().rev().take(window).collect::<Vec<_>>();
512	        windowed.reverse();
513	        let next_offset = windowed.len() as i64;
514	
515	        Ok(ApiMessagesResponse {
516	            messages: windowed.into_iter().map(api_message_from_record).collect(),
517	            total_messages,
518	            next_page: false,
519	            next_offset,
520	            next_command: None,
521	        })
522	    }
523	}
