532	fn project_lookup_aliases(name: &str, original_path: &str) -> Vec<String> {
533	    let mut aliases = Vec::new();
534	    let mut push_alias = |alias: &str| {
535	        if alias.is_empty() || alias == name {
536	            return;
537	        }
538	        if !aliases.iter().any(|existing| existing == alias) {
539	            aliases.push(alias.to_string());
540	        }
541	    };
542	
543	    if let Some(basename) = path_basename(name) {
544	        push_alias(basename);
545	    }
546	    if original_path != name
547	        && let Some(basename) = path_basename(original_path)
548	    {
549	        push_alias(basename);
550	    }
551	
552	    let canonical = if name.starts_with('/') {
553	        name
554	    } else {
555	        original_path
556	    };
557	    if canonical.starts_with('/') {
558	        for alias in project_aliases(canonical) {
559	            push_alias(&alias);
560	        }
561	    }
562	
563	    aliases.sort();
564	    aliases.dedup();
565	    aliases
566	}
