568	/// Resolve a project identifier against known projects, handling Codex path normalization
569	/// and deterministic basename aliases for read commands and teleport.
570	/// When source_filter is None, searches all sources.
571	fn resolve_project(
572	    projects: &[ProjectAggregate],
573	    source_filter: Option<SourceFilter>,
574	    project: &str,
575	) -> Result<ResolvedProject> {
576	    let trimmed = project.trim();
577	    if trimmed.is_empty() {
578	        return Ok(ResolvedProject {
579	            names: vec![trimmed.to_string()],
580	        });
581	    }
582	
583	    let mut candidates = vec![trimmed.to_string()];
584	    if trimmed.starts_with('/') {
585	        let without_leading = trimmed.trim_start_matches('/');
586	        if !without_leading.is_empty() {
587	            candidates.push(without_leading.to_string());
588	        }
589	    } else {
590	        candidates.push(format!("/{trimmed}"));
591	    }
592	    candidates.sort();
593	    candidates.dedup();
594	
595	    let should_search_codex = source_filter.is_none() || source_filter == Some(SourceFilter::Codex);
596	    let should_search_claude =
597	        source_filter.is_none() || source_filter == Some(SourceFilter::Claude);
598	    let should_search_cursor =
599	        source_filter.is_none() || source_filter == Some(SourceFilter::Cursor);
600	    let should_search_grok = source_filter.is_none() || source_filter == Some(SourceFilter::Grok);
601	    let should_search_pi = source_filter.is_none() || source_filter == Some(SourceFilter::Pi);
602	
603	    let mut matched_names = Vec::new();
604	
605	    if should_search_codex {
606	        for candidate in &candidates {
607	            if let Some(project_match) = projects
608	                .iter()
609	                .find(|item| {
610	                    item.source == SourceKind::Codex
611	                        && (item.name == *candidate || item.original_path == *candidate)
612	                })
613	                .filter(|m| !matched_names.contains(&m.name))
614	            {
615	                matched_names.push(project_match.name.clone());
616	            }
617	        }
618	    }
619	
620	    if should_search_claude {
621	        for candidate in &candidates {
622	            if let Some(project_match) = projects
623	                .iter()
624	                .find(|item| {
625	                    item.source == SourceKind::Claude
626	                        && (item.name == *candidate || item.original_path == *candidate)
627	                })
628	                .filter(|m| !matched_names.contains(&m.name))
629	            {
630	                matched_names.push(project_match.name.clone());
631	            }
632	        }
633	    }
634	
635	    if should_search_cursor {
636	        for candidate in &candidates {
637	            if let Some(project_match) = projects
638	                .iter()
639	                .find(|item| {
640	                    item.source == SourceKind::Cursor
641	                        && (item.name == *candidate || item.original_path == *candidate)
642	                })
643	                .filter(|m| !matched_names.contains(&m.name))
644	            {
645	                matched_names.push(project_match.name.clone());
646	            }
647	        }
648	    }
649	
650	    if should_search_grok {
651	        for candidate in &candidates {
652	            if let Some(project_match) = projects
653	                .iter()
654	                .find(|item| {
655	                    item.source == SourceKind::Grok
656	                        && (item.name == *candidate || item.original_path == *candidate)
657	                })
658	                .filter(|m| !matched_names.contains(&m.name))
659	            {
660	                matched_names.push(project_match.name.clone());
661	            }
662	        }
663	    }
664	
665	    if should_search_pi {
666	        for candidate in &candidates {
667	            if let Some(project_match) = projects
668	                .iter()
669	                .find(|item| {
670	                    item.source == SourceKind::Pi
671	                        && (item.name == *candidate || item.original_path == *candidate)
672	                })
673	                .filter(|m| !matched_names.contains(&m.name))
674	            {
675	                matched_names.push(project_match.name.clone());
676	            }
677	        }
678	    }
679	
680	    if !matched_names.is_empty() {
681	        return Ok(ResolvedProject {
682	            names: matched_names,
683	        });
684	    }
685	
686	    let basename = path_basename(trimmed).unwrap_or(trimmed);
687	    let mut alias_matches = Vec::new();
688	    let mut alias_identities = Vec::new();
689	
690	    for item in projects {
691	        if !matches_source_filter(item.source, source_filter) {
692	            continue;
693	        }
694	        for candidate in [&item.name, &item.original_path] {
695	            if candidate.is_empty() {
696	                continue;
697	            }
698	            let matches_basename = path_basename(candidate) == Some(basename);
699	            let matches_literal = candidate == trimmed;
700	            if (matches_basename || matches_literal) && !alias_matches.contains(&item.name) {
701	                alias_matches.push(item.name.clone());
702	                let identity = if item.original_path.is_empty() {
703	                    item.name.clone()
704	                } else {
705	                    item.original_path.clone()
706	                };
707	                alias_identities.push(identity);
708	            }
709	        }
710	    }
711	
712	    alias_matches.sort();
713	    alias_matches.dedup();
714	    alias_identities.sort();
715	    alias_identities.dedup();
716	
717	    if alias_identities.len() > 1 {
718	        bail!("multiple projects matched alias {basename:?}; pass an exact project path");
719	    }
720	
721	    if !alias_matches.is_empty() {
722	        return Ok(ResolvedProject {
723	            names: alias_matches,
724	        });
725	    }
726	
727	    Ok(ResolvedProject {
728	        names: vec![project.to_string()],
729	    })
730	}
