767	fn sort_projects(projects: &mut [ProjectAggregate], sort_by: SortBy, order: SortOrder) {
768	    projects.sort_by(|a, b| {
769	        let primary = match sort_by {
770	            SortBy::Timestamp => a.last_activity.cmp(&b.last_activity),
771	            SortBy::MessageCount => a.message_count.cmp(&b.message_count),
772	        };
773	        let secondary = match sort_by {
774	            SortBy::Timestamp => a.message_count.cmp(&b.message_count),
775	            SortBy::MessageCount => a.last_activity.cmp(&b.last_activity),
776	        };
777	
778	        apply_sort_order(primary, order)
779	            .then_with(|| apply_sort_order(secondary, order))
780	            .then_with(|| a.name.cmp(&b.name))
781	            .then_with(|| a.original_path.cmp(&b.original_path))
782	            .then_with(|| a.source.cmp(&b.source))
783	    });
784	}
