823	fn sort_messages(
824	    messages: &mut [MessageRecord],
825	    sort_by: SortBy,
826	    order: SortOrder,
827	    session_message_counts: &HashMap<SessionMessageCountKey, i32>,
828	) {
829	    messages.sort_by(|a, b| {
830	        let primary = match sort_by {
831	            SortBy::Timestamp => message_chronological_cmp(a, b),
832	            SortBy::MessageCount => message_session_count(a, session_message_counts)
833	                .cmp(&message_session_count(b, session_message_counts)),
834	        };
835	        let secondary = match sort_by {
836	            SortBy::Timestamp => Ordering::Equal,
837	            SortBy::MessageCount => message_chronological_cmp(a, b),
838	        };
839	
840	        apply_sort_order(primary, order)
841	            .then_with(|| apply_sort_order(secondary, order))
842	            .then_with(|| a.session_id.cmp(&b.session_id))
843	    });
844	}
