897	fn apply_pagination<T>(items: Vec<T>, limit: Option<usize>, offset: usize) -> Vec<T> {
898	    let start = offset.min(items.len());
899	    let end = match limit {
900	        Some(limit) => (start + limit).min(items.len()),
901	        None => items.len(),
902	    };
903	    items.into_iter().skip(start).take(end - start).collect()
904	}
905	
906	fn apply_message_index_range<T>(items: Vec<T>, range: Option<MessageIndexRange>) -> Vec<T> {
907	    let Some(range) = range else {
908	        return items;
909	    };
910	    let start = range.from.unwrap_or(0).min(items.len());
911	    let end = range.to.unwrap_or(items.len()).min(items.len());
912	    if end < start {
913	        return Vec::new();
914	    }
915	    items.into_iter().skip(start).take(end - start).collect()
916	}
917	
918	fn message_index_range_len(len: usize, range: MessageIndexRange) -> usize {
919	    let start = range.from.unwrap_or(0).min(len);
920	    let end = range.to.unwrap_or(len).min(len);
921	    if end < start {
922	        return 0;
923	    }
924	    end - start
925	}
