941	fn truncate_preview(value: &str, max_chars: usize) -> String {
942	    if value.chars().count() <= max_chars {
943	        return value.to_string();
944	    }
945	
946	    let byte_idx = value
947	        .char_indices()
948	        .nth(max_chars)
949	        .map(|(index, _)| index)
950	        .unwrap_or(value.len());
951	    format!("{}...", &value[..byte_idx])
952	}
